import { scale } from '../../../core/main-zc-init';
import { isUndefined } from '../../../utils/zcutils';
import { getInitialDataCount, getRaceScrollView, updateYaxisDomain } from './continuousRace-handler';

export function onBrushHandler(behaviourEventInstance, selectionManager, selection, event, race, chart) {
    var keyFrames = race.data,
        isManual = race.raceMode === 'manual',
        scroll = behaviourEventInstance.instance,
        visibleFrameStatus = chart.racing.visibleFrameStatus,
        invokeFunction = $ZC.getComponent('utils.invokeFunction');

    if (race.keyFramedRace) {
        chart.renderVisiblePointsOnly = false;
        var _frame = race.getKeyFrame(chart, keyFrames);
        if (isManual) {
            race.manualRace_manager(chart, _frame, race.manualQueue);
        } else {
            if (!(visibleFrameStatus && visibleFrameStatus.isTransitionStarted)) {
                //only if current frame is not positioned, else many transition would get registred and too late running already erro would be thrown.
                race.setData(_frame, chart);
                race.render(chart, _frame);
            }
            if (visibleFrameStatus && visibleFrameStatus.isRenderingStarted) {
                visibleFrameStatus.isTransitionStarted = true;
            }
        }
        event.allowDefault = false;
        scroll.lastScroll = selection.map(scroll.scrollPositionScale.invert);
    } else {
        if (race.isEntireAxisNeededForOrdinal && chart.dataset.getDataType('x') === 'ordinal') {
            selectionManager.point.x.domain = scroll.brushScale.domain();
        }
        var isAuto = race.raceMode === 'auto',
            index;
        if (isManual || (isAuto && !chart.racing.started)) {
            index = selectionToDataIndex(chart);
            if(chart.updating){
              chart.racing.syncTransition = null;
              updateYaxisDomain(chart, index);
            }
        }
        if (isManual || (isAuto && !chart.racing.started)) {
            chart.racing.syncTransition = null;
            //on manual brush and chart init
            if (!chart.updating) {
                race.continuousRaceInfo.index = index;
                if (isUndefined(race.continuousRaceInfo.initialValue)) {
                    race.continuousRaceInfo.initialValue = getInitialDataCount(chart);
                    var maxcount =
                        chart.dataset.getDataType('x') == 'ordinal'
                            ? chart.scroll.brushScale.domain().length
                            : chart.racing.continuousRaceInfo.raceScaleX.domain().length;
                    if (maxcount <= race.continuousRaceInfo.initialValue + 1) {
                        race.continuousRaceInfo.initialValue = 1;
                    }
                }
                
            }
            updateYaxisDomain(chart);
            
            //scrollView update
            let { minRange, maxRange } = chart.systemConf.chart.axes.xaxis;
            if (!(minRange != undefined && maxRange != undefined)) {
                chart.scrollView = null;
                //when minrange alone is given, inorder to get the behaviour properly, we need to set this to null.
            }
            chart.racing.scrollView = getRaceScrollView(chart, chart.dataset.getDataType('x') === 'ordinal', null, false);
            // chart.racing.scrollView = null; //used to control the filtering of data
            chart.racing.syncTransition = null;
        }
        if (!(visibleFrameStatus && visibleFrameStatus.isTransitionStarted) || !isAuto) {
            invokeFunction(race.events.onInit, race, chart);
            // if(!chart.updating){
            event.allowDefault = true;
            // }
            chart.scrolling_ = false;
            chart.scrolling = false;
        }

        if (visibleFrameStatus && visibleFrameStatus.isRenderingStarted) {
            visibleFrameStatus.isTransitionStarted = true;
        }
        scroll.lastScroll = selection.map(scroll.scrollPositionScale.invert);
    }
    if (chart.scroll) {
        bindEventToScroll.call(race, chart);
    }
}

function bindEventToScroll(chart) {
    var _this = this,
        scroll = chart.scroll,
        instance = scroll.brushInstance,
        isEventBinded = instance.parent_group.on('mousedown touchstart');

    if (instance && !isEventBinded) {
        var range = instance.getRange(),
            maxStep = range[1] - range[0];
        instance.addHook('end', function(event) {
            if (event.selection[1] >= maxStep) {
                _this.autoPlayMode = 'replay';
            }
        });

        instance.parent_group.on(
            'mousedown touchstart',
            async function(event) {
                if (!(chart.chartRendered || (chart.racing.started && !chart.racing.interrupt) || chart.racing.ended)) {
                    return;
                }
                var _this = chart.racing;
                _this.started = false;
                _this.ended = true;
                _this.raceMode = 'manual';
                _this.autoPlayMode = 'play';
                chart.scroll.visiblePointCount = null;
                var scroll = chart.behaviouralEvents.eventManager.behaviours.CHART_SCROLL,
                    invokeFunction = $ZC.getComponent('utils.invokeFunction');
                if (scroll) {
                    scroll.instance.brushInstance._raceInProgress = false;
                }
                invokeFunction(_this.events.onInterrupt, _this, chart);

                if (chart.scroll.brushInstance._selection.on('click touchstart')) {
                    var brush = chart.scroll.brushInstance,
                        type = brush.options.type;
                    let [x, y] = d3.pointer(event, brush.parent_group.node()),
                        val = type ? (type == 'x' ? x : y) : x;
                    if (val > 0) {
                        chart.racing.interrupt = true;
                        chart.scroll.brushInstance._selection.on('click touchstart')(event);
                        chart.racing.interrupt = false;
                    }
                }
            },
            true
        );
    }
}

function selectionToDataIndex(chart){
  var scroll = chart.scroll,
      selection = scroll && scroll.brushInstance && scroll.brushInstance.getSelection();
  if (chart.dataset.getDataType('x') == 'ordinal') {
      return scale.invert(
          chart.dataset.getDataType('x'),
          { x: selection[1], y: 0 },
          chart.scroll.brushScale,
          chart.axes.rotated,
          'x',
          chart.axes.x.reversed,
          null,
          {
              selection: selection
          },
          chart,
          false
      ); //updating continuousRaceInfo.index on manual brush, only then when played after manual brush race will be continued.
  } else {
      return Math.floor(chart.racing.continuousRaceInfo.raceScaleX(selection[1]));
  }
}
